1	%% NR Cell Performance — 128T128R Downlink MU-MIMO (Rel-19 eTypeII)
2	% Evaluates DL MU-MIMO system performance using abstract PHY (L2SM),
3	% 128-antenna gNB with eTypeII-r19 codebook (TS 38.214 §5.2.2.2.5a).
4	%
5	% Author: ThangTQ23 — VSI, 2026-04
6	
7	%% 1. Simulation Setup
8	
9	% Prepend local patched wirelessnetwork + 5g toolbox overrides so that
10	% 128T-capable nrGNB (allows NumTransmitAntennas up to 128) and the
11	% eTypeII-r19 PHY stack are found before the installed support packages.
12	projectRoot = fileparts(mfilename('fullpath'));
13	addpath(genpath(fullfile(projectRoot, 'wirelessnetwork')), '-begin');
14	addpath(genpath(fullfile(projectRoot, '5g')),              '-begin');
15	
16	wirelessnetworkSupportPackageCheck
17	
18	% ── PMI / CQI reporting mode for 128T eTypeII-r19 ──────────────────────────
19	% 'Wideband' : single precoder + single CQI across full BW.
20	%              Fastest simulation; suitable for quick sweeps or low-spec PCs.
21	% 'Subband'  : per-subband precoder (PMI) + per-subband CQI (Phase 4b).
22	%              Each subband = 4 RBs (TS 38.214 Table 5.2.1.4-2, NRB∈[24,72]).
23	%              Best frequency-selective accuracy; ~6× slower LQM compute.
24	pmiCQIMode = "Subband";   % <-- change to "Wideband" for faster runs
25	
26	rng("default")
27	numFrameSimulation = 50;
28	networkSimulator   = wirelessNetworkSimulator.init;
29	
30	%% 2. gNB Configuration
31	% 128T128R massive MIMO, TDD, 4.9 GHz n79, 10 MHz / 30 kHz SCS
32	% (Use channelBW = 100e6 for production; 10 MHz here for fast simulation.)
33	
34	gNBPosition  = [0 0 30];       % [x y z] metres
35	duplexType   = "TDD";
36	numUEs       = 64;             % total UEs — defined here so SRSPeriodicityUE can auto-scale
37	
38	carrierFreq  = 4.9e9;          % n79 band centre frequency (Hz)
39	channelBW    = 10e6;           % channel bandwidth (Hz)
40	scs          = 30e3;           % subcarrier spacing (Hz)
41	
42	% Valid NRB per 3GPP TS 38.104 Table 5.3.2-1 for FR1 30 kHz SCS:
43	%   5 MHz→11, 10 MHz→24, 15 MHz→38, 20 MHz→51, 40 MHz→106, 100 MHz→273
44	numRB = 24;   % matches channelBW = 10 MHz, SCS = 30 kHz
45	
46	gNB = nrGNB( ...
47	    Position             = gNBPosition, ...
48	    TransmitPower        = 60, ...
49	    CarrierFrequency     = carrierFreq, ...
50	    ChannelBandwidth     = channelBW, ...
51	    SubcarrierSpacing    = scs, ...
52	    NumResourceBlocks    = numRB, ...
53	    NumTransmitAntennas  = 128, ...
54	    NumReceiveAntennas   = 128, ...
55	    DuplexMode           = duplexType, ...
56	    ReceiveGain          = 11, ...
57	    SRSPeriodicityUE     = 20);
58	
59	disp("gNB: " + duplexType + ", " + carrierFreq/1e9 + " GHz, " + ...
60	     channelBW/1e6 + " MHz, NRB=" + numRB + ", 128T128R");
61	
62	%% 3. Scheduler Configuration
63	% CSI measurement source: "CSI-RS" (eTypeII-r19 feedback) or "SRS" (TDD reciprocity)
64	
65	csiMeasurementSignalDLType = "CSI-RS";
66	allocationType             = 0;   % RAT-0 (RBG-based)
67	
68	% CSI-RS mode fields: SemiOrthogonalityFactor, MinCQI (not MinSINR — that is SRS-only)
69	muMIMOConfiguration = struct( ...
70	    MaxNumUsersPaired       = 12, ...
71	    MaxNumLayers            = 24, ...
72	    MinNumRBs               = 2, ...
73	    SemiOrthogonalityFactor = 0.5, ...
74	    MinCQI                  = 1);
75	
76	configureScheduler(gNB, ...
77	    ResourceAllocationType = allocationType, ...
78	    MaxNumUsersPerTTI      = 32, ...
79	    MUMIMOConfigDL         = muMIMOConfiguration, ...
80	    CSIMeasurementSignalDL = csiMeasurementSignalDLType);
81	
82	%% 4. UE Deployment
83	% UEs scattered across a 120° sector, min 50 m – max 500 m from gNB.
84	% Distance drawn from uniform distribution on area (pdf ∝ r) via sqrt-trick
85	% so that UEs are spread evenly over the sector area, not clustered near gNB.
86	
87	ueRxGain       = 0;
88	ueNumTxAnt     = 4;
89	ueNumRxAnt     = 4;
90	
91	rMin = 50;   rMax = 500;   % metres
92	azDeg  = -60 + 120 .* rand(numUEs, 1);                      % uniform azimuth in [-60°, +60°]
93	rDist  = sqrt(rMin^2 + (rMax^2 - rMin^2) .* rand(numUEs, 1)); % uniform on area (pdf ∝ r)
94	[xPos, yPos, zPos] = sph2cart(deg2rad(azDeg), zeros(numUEs,1), rDist);
95	uePositions = [xPos, yPos, zPos] + gNBPosition;
96	ueNames     = "UE-" + (1:numUEs);
97	
98	UEs = nrUE( ...
99	    Name                = ueNames, ...
100	    Position            = uePositions, ...
101	    ReceiveGain         = ueRxGain, ...
102	    NumTransmitAntennas = ueNumTxAnt, ...
103	    NumReceiveAntennas  = ueNumRxAnt);
104	
105	% Apply PMI/CQI mode before connectUE so nrNodeValidation picks it up.
106	gNB.PMICQIMode = pmiCQIMode;
107	
108	connectUE(gNB, UEs, FullBufferTraffic = "DL", CSIReportPeriodicity = 10);
109	
110	%% 5. Network Simulator — Add Nodes
111	
112	addNodes(networkSimulator, gNB);
113	addNodes(networkSimulator, UEs);
114	
115	%% 6. CDL Channel Model
116	% CDL-B, 100 ns delay spread, 5 Hz Doppler (frequency-selective, rank-friendly)
117	
118	channelConfig = struct( ...
119	    DelayProfile        = "CDL-B", ...
120	    DelaySpread         = 100e-9, ...
121	    MaximumDopplerShift = 5);
122	
123	channels = hNRCreateCDLChannels(channelConfig, gNB, UEs);
124	customChannelModel = hNRCustomChannelModel(channels);
125	addChannelModel(networkSimulator, @customChannelModel.applyChannelModel);
126	
127	%% 7. Logging and Visualization
128	
129	enableTraces = true;
130	
131	if enableTraces
132	    simSchedulingLogger = helperNRSchedulingLogger(numFrameSimulation, gNB, UEs);
133	    simPhyLogger        = helperNRPhyLogger(numFrameSimulation, gNB, UEs);
134	end
135	
136	numMetricPlotUpdates = 200;
137	metricsVisualizer = helperNRMetricsVisualizer(gNB, UEs, ...
138	    RefreshRate         = numMetricPlotUpdates, ...
139	    PlotSchedulerMetrics = true, ...
140	    PlotPhyMetrics      = false, ...
141	    PlotCDFMetrics      = true, ...
142	    LinkDirection       = 0);
143	
144	simulationLogFile = "simulationLogs";
145	
146	%% 8. Simulation Conditions Summary
147	
148	slotsPerSubfm  = scs / 15e3;           % slots per subframe (2 for 30 kHz SCS)
149	slotDurMs      = 1 / slotsPerSubfm;    % ms per slot
150	slotsPerFrm    = 10 * slotsPerSubfm;   % slots per 10-ms frame
151	csiPeriodicity = 10;                   % slots (set in connectUE call above)
152	csiPeriodMs    = csiPeriodicity * slotDurMs;
153	numCSIEvents   = floor(numFrameSimulation * slotsPerFrm / csiPeriodicity);
154	
155	if strcmpi(pmiCQIMode, 'Subband')
156	    if numRB >= 145; sbSize = 16; elseif numRB >= 73; sbSize = 8; else; sbSize = 4; end
157	    numSubbands = ceil(numRB / sbSize);
158	    oh_cqi = 4 + 2*(numSubbands - 1);   % wideband base + differential per extra subband
159	    modeStr = sprintf('Subband (PMI+CQI) | %d × %d RBs', numSubbands, sbSize);
160	else
161	    sbSize = numRB;  numSubbands = 1;  oh_cqi = 4;
162	    modeStr = 'Wideband (PMI+CQI)';
163	end
164	oh_ri = 2;  oh_pmi = 20;   % RI: ceil(log2(4)); PMI approx (eTypeII-r19, L=2)
165	oh_total = oh_ri + oh_cqi + oh_pmi;
166	
167	sep = repmat('═', 1, 67);
168	fprintf('\n%s\n', sep);
169	fprintf('  SIMULATION CONDITIONS — 128T128R MU-MIMO DL, Rel-19 eTypeII\n');
170	fprintf('%s\n', sep);
171	fprintf('  System\n');
172	fprintf('    gNB  : %dT/%dR | %.1f GHz (n79) | %s | %d dBm Tx\n', ...
173	    gNB.NumTransmitAntennas, gNB.NumReceiveAntennas, ...
174	    carrierFreq/1e9, duplexType, 34);
175	fprintf('           BW=%.0f MHz | NRB=%d | SCS=%.0f kHz | Rx Gain=11 dB\n', ...
176	    channelBW/1e6, numRB, scs/1e3);
177	fprintf('    UE   : %d nodes | %dTx/%dRx | R=500 m | Az=[-60°,+60°] | Rx Gain=0 dB\n', ...
178	    numUEs, ueNumTxAnt, ueNumRxAnt);
179	fprintf('  Channel  : %s | RMS delay=%.0f ns | f_D=%.0f Hz\n', ...
180	    channelConfig.DelayProfile, channelConfig.DelaySpread*1e9, channelConfig.MaximumDopplerShift);
181	fprintf('  Scheduler\n');
182	fprintf('    Source : %s | MU-MIMO ≤%d paired / ≤%d layers | RAT-%d\n', ...
183	    csiMeasurementSignalDLType, muMIMOConfiguration.MaxNumUsersPaired, ...
184	    muMIMOConfiguration.MaxNumLayers, allocationType);
185	fprintf('             MinCQI=%d | Semiortho=%.1f | SRS period=20 ms\n', ...
186	    muMIMOConfiguration.MinCQI, muMIMOConfiguration.SemiOrthogonalityFactor);
187	fprintf('  CSI Feedback\n');
188	fprintf('    Signal   : CSI-RS (4×32-port Row-18 resources ≡ 128T)\n');
189	fprintf('    Codebook : eTypeII-r19 | Panel [1×16×4] | L=2 beams | PC=1\n');
190	fprintf('    Mode     : %s\n', modeStr);
191	fprintf('    Period   : %d slots (%.1f ms) → ~%d reports/UE in %d frames\n', ...
192	    csiPeriodicity, csiPeriodMs, numCSIEvents, numFrameSimulation);
193	fprintf('    OH est.  : RI=%d + CQI=%d + PMI≈%d ≈ %d bits/report\n', ...
194	    oh_ri, oh_cqi, oh_pmi, oh_total);
195	fprintf('    [Live CSI events printed below for UE-1 and UE-2 only]\n');
196	fprintf('  Simulation : %d frames | %.0f ms | full-buffer DL | logging=%s\n', ...
197	    numFrameSimulation, numFrameSimulation*10, upper(char(string(enableTraces))));
198	fprintf('%s\n\n', sep);
199	
200	%% 9. Run Simulation
201	
202	simulationTime = numFrameSimulation * 1e-2;   % seconds
203	run(networkSimulator, simulationTime);
204	
205	%% 10. Results — KPI Summary
206	% Display cell throughput, spectral efficiency, and BLER ECDF.
207	
208	displayPerformanceIndicators(metricsVisualizer);
209	
210	%% 11. Save Traces
211	
212	if enableTraces
213	    simulationLogs = cell(1,1);
214	    if gNB.DuplexMode == "FDD"
215	        logInfo = struct(DLTimeStepLogs=[], ULTimeStepLogs=[], ...
216	                         SchedulingAssignmentLogs=[], PhyReceptionLogs=[]);
217	        [logInfo.DLTimeStepLogs, logInfo.ULTimeStepLogs] = ...
218	            getSchedulingLogs(simSchedulingLogger);
219	    else  % TDD
220	        logInfo = struct(TimeStepLogs=[], SchedulingAssignmentLogs=[], ...
221	                         PhyReceptionLogs=[]);
222	        logInfo.TimeStepLogs = getSchedulingLogs(simSchedulingLogger);
223	    end
224	    logInfo.SchedulingAssignmentLogs = getGrantLogs(simSchedulingLogger);
225	    logInfo.PhyReceptionLogs         = getReceptionLogs(simPhyLogger);
226	    simulationLogs{1} = logInfo;
227	    save(simulationLogFile, "simulationLogs");
228	end
229	
230	%% 11b. Grant / MCS Summary — gNB Downlink Decisions
231	
232	if enableTraces
233	    colMap   = simSchedulingLogger.GrantLogsColumnIndexMap;
234	    % getGrantLogs prepends an alphabetical header row; skip it, use colMap for column indices.
235	    grantRaw = logInfo.SchedulingAssignmentLogs(2:end, :);
236	
237	    rntiCol  = colMap('RNTI');
238	    mcsCol   = colMap('MCS Index');
239	    lyrCol   = colMap('NumLayers');
240	    typeCol  = colMap('Grant Type');
241	
242	    isDL   = strcmp(grantRaw(:, typeCol), 'DL');
243	    dlData = grantRaw(isDL, :);
244	    nDL    = sum(isDL);
245	
246	    sep2 = repmat('─', 1, 67);
247	    fprintf('\n%s\n', sep2);
248	    fprintf('  gNB DL Grant Summary  (%d grants | %d frames | %s mode)\n', ...
249	        nDL, numFrameSimulation, pmiCQIMode);
250	    fprintf('%s\n', sep2);
251	    fprintf('  %-6s  %7s  %8s  %8s  %8s  %8s\n', ...
252	        'UE', 'Grants', 'MCS avg', 'MCS min', 'MCS max', 'Lyr avg');
253	    fprintf('%s\n', sep2);
254	    for ueIdx = 1:numUEs
255	        mask = cell2mat(dlData(:, rntiCol)) == ueIdx;
256	        if ~any(mask); continue; end
257	        mcsV = cell2mat(dlData(mask, mcsCol));
258	        lyrV = cell2mat(dlData(mask, lyrCol));
259	        fprintf('  UE-%-3d  %7d  %8.1f  %8d  %8d  %8.1f\n', ...
260	            ueIdx, sum(mask), mean(mcsV), min(mcsV), max(mcsV), mean(lyrV));
261	    end
262	    fprintf('%s\n\n', sep2);
263	end
264	
265	%% 12. MU-MIMO Pairing Analysis — UEs per RB Distribution
266	% Histogram shows how often multiple UEs share the same RB in DL slots.
267	
268	if enableTraces
269	    avgNumUEsPerRB = calculateAvgUEsPerRBDL(logInfo, gNB.NumResourceBlocks, ...
270	                                             allocationType, duplexType);
271	    figure;
272	    histogram(avgNumUEsPerRB, BinWidth=0.1);
273	    title("Distribution of Average Number of UEs per RB in DL Slots");
274	    xlabel("Average Number of UEs per RB");
275	    ylabel("Number of Occurrences");
276	    grid on;
277	end
278	
279	%% Local Function
280	
281	function avgUEsPerRB = calculateAvgUEsPerRBDL(logInfo, numResourceBlocks, ratType, duplexMode)
282	    % Returns average number of UE nodes per RB for each DL slot.
283	    % Supports RAT-0 (RBG-based) and RAT-1 (contiguous-RB-based) allocation.
284	
285	    if strcmp(duplexMode, 'TDD')
286	        timeStepLogs    = logInfo.TimeStepLogs;
287	        freqAllocations = timeStepLogs(:, 5);
288	    else
289	        timeStepLogs    = logInfo.DLTimeStepLogs;
290	        freqAllocations = timeStepLogs(:, 4);
291	    end
292	
293	    numOfSlots = size(timeStepLogs, 1) - 1;
294	
295	    if ~ratType
296	        % Derive per-RBG sizes per TS 38.214
297	        numRBG       = size(freqAllocations{2}, 2);
298	        P            = ceil(numResourceBlocks / numRBG);
299	        numRBsPerRBG = P * ones(1, numRBG);
300	        remainder    = mod(numResourceBlocks, P);
301	        if remainder > 0
302	            numRBsPerRBG(end) = remainder;
303	        end
304	    end
305	
306	    avgUEsPerRB = zeros(1, numOfSlots);
307	
308	    for slotIdx = 1:numOfSlots
309	        % Skip UL slots in TDD
310	        if strcmp(duplexMode, 'TDD') && ~strcmp(timeStepLogs{slotIdx+1, 4}, 'DL')
311	            continue;
312	        end
313	
314	        freqAllocation = freqAllocations{slotIdx + 1};
315	
316	        if ~ratType
317	            % RAT-0: weight each RBG by its RB count
318	            totalUniqueUEs = sum(arrayfun( ...
319	                @(i) nnz(freqAllocation(:,i) > 0) * numRBsPerRBG(i), ...
320	                1:length(numRBsPerRBG)));
321	            avgUEsPerRB(slotIdx) = totalUniqueUEs / numResourceBlocks;
322	        else
323	            % RAT-1: count UEs per contiguous RB allocation
324	            ueRBUsage = zeros(1, numResourceBlocks);
325	            for ueIdx = 1:size(freqAllocation, 1)
326	                startRB = freqAllocation(ueIdx, 1);
327	                numRBs  = freqAllocation(ueIdx, 2);
328	                ueRBUsage(startRB+1 : startRB+numRBs) = ...
329	                    ueRBUsage(startRB+1 : startRB+numRBs) + 1;
330	            end
331	            avgUEsPerRB(slotIdx) = mean(ueRBUsage(ueRBUsage > 0));
332	        end
333	    end
334	
335	    % Remove zero entries (UL slots)
336	    avgUEsPerRB = avgUEsPerRB(avgUEsPerRB > 0);
337	end
338

