%% NR Cell Performance — 128T128R Downlink MU-MIMO (Rel-19 eTypeII)
% Evaluates DL MU-MIMO system performance using abstract PHY (L2SM),
% 128-antenna gNB with eTypeII-r19 codebook (TS 38.214 §5.2.2.2.5a).
%
% Author: ThangTQ23 — VSI, 2026-04

%% 1. Simulation Setup

% Prepend local patched wirelessnetwork + 5g toolbox overrides so that
% 128T-capable nrGNB (allows NumTransmitAntennas up to 128) and the
% eTypeII-r19 PHY stack are found before the installed support packages.
projectRoot = fileparts(mfilename('fullpath'));
addpath(genpath(fullfile(projectRoot, 'wirelessnetwork')), '-begin');
addpath(genpath(fullfile(projectRoot, '5g')),              '-begin');

wirelessnetworkSupportPackageCheck

% ── PMI / CQI reporting mode for 128T eTypeII-r19 ──────────────────────────
% 'Wideband' : single precoder + single CQI across full BW.
%              Fastest simulation; suitable for quick sweeps or low-spec PCs.
% 'Subband'  : per-subband precoder (PMI) + per-subband CQI (Phase 4b).
%              Each subband = 4 RBs (TS 38.214 Table 5.2.1.4-2, NRB∈[24,72]).
%              Best frequency-selective accuracy; ~6× slower LQM compute.
pmiCQIMode = "Subband";   % <-- change to "Wideband" for faster runs

rng("default")
numFrameSimulation = 50;
networkSimulator   = wirelessNetworkSimulator.init;

%% 2. gNB Configuration
% 128T128R massive MIMO, TDD, 4.9 GHz n79, 10 MHz / 30 kHz SCS
% (Use channelBW = 100e6 for production; 10 MHz here for fast simulation.)

gNBPosition  = [0 0 30];       % [x y z] metres
duplexType   = "TDD";
numUEs       = 64;             % total UEs — defined here so SRSPeriodicityUE can auto-scale

carrierFreq  = 4.9e9;          % n79 band centre frequency (Hz)
channelBW    = 10e6;           % channel bandwidth (Hz)
scs          = 30e3;           % subcarrier spacing (Hz)

% Valid NRB per 3GPP TS 38.104 Table 5.3.2-1 for FR1 30 kHz SCS:
%   5 MHz→11, 10 MHz→24, 15 MHz→38, 20 MHz→51, 40 MHz→106, 100 MHz→273
numRB = 24;   % matches channelBW = 10 MHz, SCS = 30 kHz

gNB = nrGNB( ...
    Position             = gNBPosition, ...
    TransmitPower        = 60, ...
    CarrierFrequency     = carrierFreq, ...
    ChannelBandwidth     = channelBW, ...
    SubcarrierSpacing    = scs, ...
    NumResourceBlocks    = numRB, ...
    NumTransmitAntennas  = 128, ...
    NumReceiveAntennas   = 128, ...
    DuplexMode           = duplexType, ...
    ReceiveGain          = 11, ...
    SRSPeriodicityUE     = 20);

disp("gNB: " + duplexType + ", " + carrierFreq/1e9 + " GHz, " + ...
     channelBW/1e6 + " MHz, NRB=" + numRB + ", 128T128R");

%% 3. Scheduler Configuration
% CSI measurement source: "CSI-RS" (eTypeII-r19 feedback) or "SRS" (TDD reciprocity)

csiMeasurementSignalDLType = "CSI-RS";
allocationType             = 0;   % RAT-0 (RBG-based)

% CSI-RS mode fields: SemiOrthogonalityFactor, MinCQI (not MinSINR — that is SRS-only)
muMIMOConfiguration = struct( ...
    MaxNumUsersPaired       = 12, ...
    MaxNumLayers            = 24, ...
    MinNumRBs               = 2, ...
    SemiOrthogonalityFactor = 0.5, ...
    MinCQI                  = 1);

configureScheduler(gNB, ...
    ResourceAllocationType = allocationType, ...
    MaxNumUsersPerTTI      = 32, ...
    MUMIMOConfigDL         = muMIMOConfiguration, ...
    CSIMeasurementSignalDL = csiMeasurementSignalDLType);

%% 4. UE Deployment
% UEs scattered across a 120° sector, min 50 m – max 500 m from gNB.
% Distance drawn from uniform distribution on area (pdf ∝ r) via sqrt-trick
% so that UEs are spread evenly over the sector area, not clustered near gNB.

ueRxGain       = 0;
ueNumTxAnt     = 4;
ueNumRxAnt     = 4;

rMin = 50;   rMax = 500;   % metres
azDeg  = -60 + 120 .* rand(numUEs, 1);                      % uniform azimuth in [-60°, +60°]
rDist  = sqrt(rMin^2 + (rMax^2 - rMin^2) .* rand(numUEs, 1)); % uniform on area (pdf ∝ r)
[xPos, yPos, zPos] = sph2cart(deg2rad(azDeg), zeros(numUEs,1), rDist);
uePositions = [xPos, yPos, zPos] + gNBPosition;
ueNames     = "UE-" + (1:numUEs);

UEs = nrUE( ...
    Name                = ueNames, ...
    Position            = uePositions, ...
    ReceiveGain         = ueRxGain, ...
    NumTransmitAntennas = ueNumTxAnt, ...
    NumReceiveAntennas  = ueNumRxAnt);

% Apply PMI/CQI mode before connectUE so nrNodeValidation picks it up.
gNB.PMICQIMode = pmiCQIMode;

connectUE(gNB, UEs, FullBufferTraffic = "DL", CSIReportPeriodicity = 10);

%% 5. Network Simulator — Add Nodes

addNodes(networkSimulator, gNB);
addNodes(networkSimulator, UEs);

%% 6. CDL Channel Model
% CDL-B, 100 ns delay spread, 5 Hz Doppler (frequency-selective, rank-friendly)

channelConfig = struct( ...
    DelayProfile        = "CDL-B", ...
    DelaySpread         = 100e-9, ...
    MaximumDopplerShift = 5);

channels = hNRCreateCDLChannels(channelConfig, gNB, UEs);
customChannelModel = hNRCustomChannelModel(channels);
addChannelModel(networkSimulator, @customChannelModel.applyChannelModel);

%% 7. Logging and Visualization

enableTraces = true;

if enableTraces
    simSchedulingLogger = helperNRSchedulingLogger(numFrameSimulation, gNB, UEs);
    simPhyLogger        = helperNRPhyLogger(numFrameSimulation, gNB, UEs);
end

numMetricPlotUpdates = 200;
metricsVisualizer = helperNRMetricsVisualizer(gNB, UEs, ...
    RefreshRate         = numMetricPlotUpdates, ...
    PlotSchedulerMetrics = true, ...
    PlotPhyMetrics      = false, ...
    PlotCDFMetrics      = true, ...
    LinkDirection       = 0);

simulationLogFile = "simulationLogs";

%% 8. Simulation Conditions Summary

slotsPerSubfm  = scs / 15e3;           % slots per subframe (2 for 30 kHz SCS)
slotDurMs      = 1 / slotsPerSubfm;    % ms per slot
slotsPerFrm    = 10 * slotsPerSubfm;   % slots per 10-ms frame
csiPeriodicity = 10;                   % slots (set in connectUE call above)
csiPeriodMs    = csiPeriodicity * slotDurMs;
numCSIEvents   = floor(numFrameSimulation * slotsPerFrm / csiPeriodicity);

if strcmpi(pmiCQIMode, 'Subband')
    if numRB >= 145; sbSize = 16; elseif numRB >= 73; sbSize = 8; else; sbSize = 4; end
    numSubbands = ceil(numRB / sbSize);
    oh_cqi = 4 + 2*(numSubbands - 1);   % wideband base + differential per extra subband
    modeStr = sprintf('Subband (PMI+CQI) | %d × %d RBs', numSubbands, sbSize);
else
    sbSize = numRB;  numSubbands = 1;  oh_cqi = 4;
    modeStr = 'Wideband (PMI+CQI)';
end
oh_ri = 2;  oh_pmi = 20;   % RI: ceil(log2(4)); PMI approx (eTypeII-r19, L=2)
oh_total = oh_ri + oh_cqi + oh_pmi;

sep = repmat('═', 1, 67);
fprintf('\n%s\n', sep);
fprintf('  SIMULATION CONDITIONS — 128T128R MU-MIMO DL, Rel-19 eTypeII\n');
fprintf('%s\n', sep);
fprintf('  System\n');
fprintf('    gNB  : %dT/%dR | %.1f GHz (n79) | %s | %d dBm Tx\n', ...
    gNB.NumTransmitAntennas, gNB.NumReceiveAntennas, ...
    carrierFreq/1e9, duplexType, 34);
fprintf('           BW=%.0f MHz | NRB=%d | SCS=%.0f kHz | Rx Gain=11 dB\n', ...
    channelBW/1e6, numRB, scs/1e3);
fprintf('    UE   : %d nodes | %dTx/%dRx | R=500 m | Az=[-60°,+60°] | Rx Gain=0 dB\n', ...
    numUEs, ueNumTxAnt, ueNumRxAnt);
fprintf('  Channel  : %s | RMS delay=%.0f ns | f_D=%.0f Hz\n', ...
    channelConfig.DelayProfile, channelConfig.DelaySpread*1e9, channelConfig.MaximumDopplerShift);
fprintf('  Scheduler\n');
fprintf('    Source : %s | MU-MIMO ≤%d paired / ≤%d layers | RAT-%d\n', ...
    csiMeasurementSignalDLType, muMIMOConfiguration.MaxNumUsersPaired, ...
    muMIMOConfiguration.MaxNumLayers, allocationType);
fprintf('             MinCQI=%d | Semiortho=%.1f | SRS period=20 ms\n', ...
    muMIMOConfiguration.MinCQI, muMIMOConfiguration.SemiOrthogonalityFactor);
fprintf('  CSI Feedback\n');
fprintf('    Signal   : CSI-RS (4×32-port Row-18 resources ≡ 128T)\n');
fprintf('    Codebook : eTypeII-r19 | Panel [1×16×4] | L=2 beams | PC=1\n');
fprintf('    Mode     : %s\n', modeStr);
fprintf('    Period   : %d slots (%.1f ms) → ~%d reports/UE in %d frames\n', ...
    csiPeriodicity, csiPeriodMs, numCSIEvents, numFrameSimulation);
fprintf('    OH est.  : RI=%d + CQI=%d + PMI≈%d ≈ %d bits/report\n', ...
    oh_ri, oh_cqi, oh_pmi, oh_total);
fprintf('    [Live CSI events printed below for UE-1 and UE-2 only]\n');
fprintf('  Simulation : %d frames | %.0f ms | full-buffer DL | logging=%s\n', ...
    numFrameSimulation, numFrameSimulation*10, upper(char(string(enableTraces))));
fprintf('%s\n\n', sep);

%% 9. Run Simulation

simulationTime = numFrameSimulation * 1e-2;   % seconds
run(networkSimulator, simulationTime);

%% 10. Results — KPI Summary
% Display cell throughput, spectral efficiency, and BLER ECDF.

displayPerformanceIndicators(metricsVisualizer);

%% 11. Save Traces

if enableTraces
    simulationLogs = cell(1,1);
    if gNB.DuplexMode == "FDD"
        logInfo = struct(DLTimeStepLogs=[], ULTimeStepLogs=[], ...
                         SchedulingAssignmentLogs=[], PhyReceptionLogs=[]);
        [logInfo.DLTimeStepLogs, logInfo.ULTimeStepLogs] = ...
            getSchedulingLogs(simSchedulingLogger);
    else  % TDD
        logInfo = struct(TimeStepLogs=[], SchedulingAssignmentLogs=[], ...
                         PhyReceptionLogs=[]);
        logInfo.TimeStepLogs = getSchedulingLogs(simSchedulingLogger);
    end
    logInfo.SchedulingAssignmentLogs = getGrantLogs(simSchedulingLogger);
    logInfo.PhyReceptionLogs         = getReceptionLogs(simPhyLogger);
    simulationLogs{1} = logInfo;
    save(simulationLogFile, "simulationLogs");
end

%% 11b. Grant / MCS Summary — gNB Downlink Decisions

if enableTraces
    colMap   = simSchedulingLogger.GrantLogsColumnIndexMap;
    % getGrantLogs prepends an alphabetical header row; skip it, use colMap for column indices.
    grantRaw = logInfo.SchedulingAssignmentLogs(2:end, :);

    rntiCol  = colMap('RNTI');
    mcsCol   = colMap('MCS Index');
    lyrCol   = colMap('NumLayers');
    typeCol  = colMap('Grant Type');

    isDL   = strcmp(grantRaw(:, typeCol), 'DL');
    dlData = grantRaw(isDL, :);
    nDL    = sum(isDL);

    sep2 = repmat('─', 1, 67);
    fprintf('\n%s\n', sep2);
    fprintf('  gNB DL Grant Summary  (%d grants | %d frames | %s mode)\n', ...
        nDL, numFrameSimulation, pmiCQIMode);
    fprintf('%s\n', sep2);
    fprintf('  %-6s  %7s  %8s  %8s  %8s  %8s\n', ...
        'UE', 'Grants', 'MCS avg', 'MCS min', 'MCS max', 'Lyr avg');
    fprintf('%s\n', sep2);
    for ueIdx = 1:numUEs
        mask = cell2mat(dlData(:, rntiCol)) == ueIdx;
        if ~any(mask); continue; end
        mcsV = cell2mat(dlData(mask, mcsCol));
        lyrV = cell2mat(dlData(mask, lyrCol));
        fprintf('  UE-%-3d  %7d  %8.1f  %8d  %8d  %8.1f\n', ...
            ueIdx, sum(mask), mean(mcsV), min(mcsV), max(mcsV), mean(lyrV));
    end
    fprintf('%s\n\n', sep2);
end

%% 12. MU-MIMO Pairing Analysis — UEs per RB Distribution
% Histogram shows how often multiple UEs share the same RB in DL slots.

if enableTraces
    avgNumUEsPerRB = calculateAvgUEsPerRBDL(logInfo, gNB.NumResourceBlocks, ...
                                             allocationType, duplexType);
    figure;
    histogram(avgNumUEsPerRB, BinWidth=0.1);
    title("Distribution of Average Number of UEs per RB in DL Slots");
    xlabel("Average Number of UEs per RB");
    ylabel("Number of Occurrences");
    grid on;
end

%% Local Function

function avgUEsPerRB = calculateAvgUEsPerRBDL(logInfo, numResourceBlocks, ratType, duplexMode)
    % Returns average number of UE nodes per RB for each DL slot.
    % Supports RAT-0 (RBG-based) and RAT-1 (contiguous-RB-based) allocation.

    if strcmp(duplexMode, 'TDD')
        timeStepLogs    = logInfo.TimeStepLogs;
        freqAllocations = timeStepLogs(:, 5);
    else
        timeStepLogs    = logInfo.DLTimeStepLogs;
        freqAllocations = timeStepLogs(:, 4);
    end

    numOfSlots = size(timeStepLogs, 1) - 1;

    if ~ratType
        % Derive per-RBG sizes per TS 38.214
        numRBG       = size(freqAllocations{2}, 2);
        P            = ceil(numResourceBlocks / numRBG);
        numRBsPerRBG = P * ones(1, numRBG);
        remainder    = mod(numResourceBlocks, P);
        if remainder > 0
            numRBsPerRBG(end) = remainder;
        end
    end

    avgUEsPerRB = zeros(1, numOfSlots);

    for slotIdx = 1:numOfSlots
        % Skip UL slots in TDD
        if strcmp(duplexMode, 'TDD') && ~strcmp(timeStepLogs{slotIdx+1, 4}, 'DL')
            continue;
        end

        freqAllocation = freqAllocations{slotIdx + 1};

        if ~ratType
            % RAT-0: weight each RBG by its RB count
            totalUniqueUEs = sum(arrayfun( ...
                @(i) nnz(freqAllocation(:,i) > 0) * numRBsPerRBG(i), ...
                1:length(numRBsPerRBG)));
            avgUEsPerRB(slotIdx) = totalUniqueUEs / numResourceBlocks;
        else
            % RAT-1: count UEs per contiguous RB allocation
            ueRBUsage = zeros(1, numResourceBlocks);
            for ueIdx = 1:size(freqAllocation, 1)
                startRB = freqAllocation(ueIdx, 1);
                numRBs  = freqAllocation(ueIdx, 2);
                ueRBUsage(startRB+1 : startRB+numRBs) = ...
                    ueRBUsage(startRB+1 : startRB+numRBs) + 1;
            end
            avgUEsPerRB(slotIdx) = mean(ueRBUsage(ueRBUsage > 0));
        end
    end

    % Remove zero entries (UL slots)
    avgUEsPerRB = avgUEsPerRB(avgUEsPerRB > 0);
end

classdef nrUEAbstractPHY < nr5g.internal.nrUEPHY
    %nrUEAbstractPHY Implements abstract physical (PHY) layer for user equipment(UE)
    %   The class implements the abstraction specific aspects of UE PHY.
    %
    %   Note: This is an internal undocumented class and its API and/or
    %   functionality may change in subsequent releases.

    %   Copyright 2022-2024 The MathWorks, Inc.

    properties (Access = private)
        %L2SM Link-to-system-mapping (L2SM) context
        L2SM
    end

    methods
        function obj = nrUEAbstractPHY(param, notificationFcn)
            %nrUEAbstractPHY Construct a UE PHY object
            %   OBJ = nrUEAbstractPHY(PARAM,NOTIFICATIONFCN) constructs a UE PHY object.
            %
            %   PARAM is a structure with the fields:
            %     TransmitPower       - UE Tx power in dBm
            %     NumTransmitAntennas - Number of Tx antennas on the UE
            %     NumReceiveAntennas  - Number of Rx antennas on the UE
            %     NoiseFigure         - Noise figure
            %     ReceiveGain         - Receiver gain at UE in dBi
            %
            %   NOTIFICATIONFCN - It is a handle of the node's processEvents
            %   method

            obj = obj@nr5g.internal.nrUEPHY(param, notificationFcn); % Call base class constructor

            % NR packet param
            obj.PacketStruct.Abstraction = true; % Abstracted PHY
            obj.PacketStruct.Metadata = struct('NCellID', [], 'RNTI', [], 'PrecodingMatrix', [], ...
                'NumSamples', [], 'Channel', obj.PacketStruct.Metadata.Channel);
        end

        function addConnection(obj, connectionConfig)
            %addConnection Configures the UE PHY with connection information
            %   connectionConfig is a structure including the following
            %   fields:
            %       RNTI                     - Radio network temporary identifier
            %                                  specified within [1, 65522]. Refer
            %                                  table 7.1-1 in 3GPP TS 38.321 version 18.1.0
            %       NCellID                  - Physical cell ID. values: 0 to 1007 (TS 38.211, sec 7.4.2.1)
            %       DuplexMode               - "FDD" or "TDD"
            %       SubcarrierSpacing        - Subcarrier spacing
            %       NumResourceBlocks        - Number of resource blocks (RBs)
            %       NumHARQ                  - Number of HARQ processes on UE
            %       ChannelBandwidth         - DL or UL channel bandwidth in Hz
            %       DLCarrierFrequency       - DL carrier frequency
            %       ULCarrierFrequency       - UL carrier frequency
            %       CSIReportConfiguration   - CSI report configuration

            addConnection@nr5g.internal.nrUEPHY(obj, connectionConfig);
            % Initialize L2SM to hold PDSCH, CSI-RS and inter-user interferer context
            obj.L2SM = nr5g.internal.L2SM.initialize(obj.CarrierConfig, connectionConfig.NumHARQ, 1);
            obj.L2SMCSI = nr5g.internal.L2SM.initialize(obj.CarrierConfig);
            obj.L2SMIUI = nr5g.internal.L2SM.initialize(obj.CarrierConfig);
        end

        function data = puschData(obj, puschInfo, macPDU)
            % Return the MAC packet without any PHY processing

            if isempty(macPDU)
                % MAC PDU not sent by MAC, which indicates retransmission. Get the MAC PDU
                % from the HARQ buffers
                data = obj.HARQBuffers{puschInfo.HARQID+1};
            else
                % New transmission. Buffer the transport block
                data = macPDU;
                obj.HARQBuffers{puschInfo.HARQID+1} = macPDU;
            end
        end

        function data = srsData(~, ~)
            % Return empty as abstract PHY does not send any SRS waveform

            data = [];
        end

        function [macPDU, crcFlag, sinr] = decodePDSCH(obj, pdschInfo, pktStartTime, pktEndTime, carrierConfigInfo)
            % Return the decoded MAC PDU along with the crc result

            % Read all the relevant packets (i.e either of interest or sent on same
            % carrier frequency) received during the PDSCH reception
            packetInfoList = packetList(obj.RxBuffer, pktStartTime, pktEndTime);

            % Eliminate any PDSCH packets which are not sent on the overlapping resource
            % blocks as the PDSCH of interest. Also, separate out PDSCH of interest
            numPkts = numel(packetInfoList);
            interferingPackets = packetInfoList;
            prbSetPacket = pdschInfo.PDSCHConfig.PRBSet;
            numRBPacket = numel(prbSetPacket);
            packetOfInterest = [];
            intfPktCount=0;
            for pktIdx = 1:numPkts
                metadata = packetInfoList(pktIdx).Metadata;
                if (metadata.PacketType == obj.PXSCHPacketType) % Check for PDSCH
                    if (carrierConfigInfo.NCellID == metadata.NCellID) && ... % Check for PDSCH of interest
                            (pdschInfo.PDSCHConfig.RNTI == metadata.RNTI)
                        packetOfInterest = packetInfoList(pktIdx);
                    else
                        prbSetInterferer = metadata.PacketConfig.PRBSet;
                        isMatched = false;
                        numRBInterferer = numel(prbSetInterferer);
                        % Check for interfering packets
                        for i=1:numRBPacket
                            rbOfInterest = prbSetPacket(i);
                            for j=1:numRBInterferer
                                interferingRB = prbSetInterferer(j);
                                if interferingRB == rbOfInterest
                                    isMatched = true; % Packet is an interfering one
                                    intfPktCount = intfPktCount+1;
                                    interferingPackets(intfPktCount) = packetInfoList(pktIdx);
                                    break;
                                elseif interferingRB>rbOfInterest
                                    % The other values in the interfering
                                    % RB set are only going to be bigger
                                    % than current interfering RB
                                    break;
                                end
                            end
                            if isMatched
                                break;
                            end
                        end
                    end
                end
            end
            interferingPackets = interferingPackets(1:intfPktCount);

            % Estimate channel for all for relevant packets i.e. packet of interest and
            % interferers (inter-cell interferers and inter-user interferers)
            [estChannelGrid, estChannelGridIntf] = estimateChannelGrid(obj, packetOfInterest, ...
                interferingPackets, carrierConfigInfo);

            % Read MAC PDU
            macPDU = packetOfInterest.Data;

            % Calculate crc result using l2sm
            [crcFlag, sinr] = l2smCRC(obj, packetOfInterest, interferingPackets, estChannelGrid, ...
                estChannelGridIntf, pdschInfo, carrierConfigInfo);
        end

        function [dlRank, pmiSet, cqi, precodingMatrix, sinr] = decodeCSIRS(obj, csirsConfig, pktStartTime, pktEndTime, carrierConfigInfo)
            % Return CSI-RS measurement.
            %
            % ThangTQ23_128T128R_Rel19: For 128T, four Row-18 (32-port) CSI-RS
            % resources are spread across 2 slots (R0/R1 at slot+0, R2/R3 at
            % slot+1).  Each call to decodeCSIRS accumulates one resource into
            % obj.CSIRSChannelBuffer.  PMI selection (nrRISelect + LQM + CQI)
            % runs only when all 4 resources are buffered.  Before that, the
            % function returns dlRank = -1 (sentinel) so that csirsRx() defers
            % the MAC indication.

            % ── Step 1: find packet + estimate channel ──────────────────────
            [csirsPacket, interferingPackets] = packetListIntfBuffer(obj, obj.CSIRSPacketType, ...
                pktStartTime, pktEndTime);

            nVar = calculateThermalNoise(obj);
            obj.GNBReceivedPower = csirsPacket.Power;

            rnti = obj.RNTI;
            packetOfInterest = [];
            for pktIdx = 1:numel(csirsPacket)
                if any(rnti == csirsPacket(pktIdx).Metadata.RNTI)
                    packetOfInterest = csirsPacket(pktIdx);
                    break;
                end
            end

            [estChannelGrid, estChannelGridIntf] = estimateChannelGrid(obj, packetOfInterest, ...
                interferingPackets, carrierConfigInfo);

            intf = prepareLQMInputIntf(obj, obj.L2SMIUI, interferingPackets, estChannelGridIntf, ...
                carrierConfigInfo, nVar);

            % ── Step 2: 128T accumulation path (Row 18 = 32-port CDM8 resource)
            % ThangTQ23_128T128R_Rel19: aggregate H across all resources
            % before running PMI.  numResources128T = 4 for 128T.
            numResources128T = 4;
            if csirsConfig.RowNumber == 18 && csirsConfig.NumCSIRSPorts == 32
                % ThangTQ23_128T128R_Rel19: In abstract PHY, nrPerfectChannelEstimate
                % already returns the full 128-port channel [K x L x nRx x 128]
                % for every CSI-RS resource event (gNB has 128 antennas).
                % DO NOT concatenate along dim-4; instead accumulate as a running
                % average across all 4 resources for improved noise averaging.
                buf = obj.CSIRSChannelBuffer;
                if buf.count == 0
                    buf.H = estChannelGrid;
                else
                    buf.H = (buf.H * buf.count + estChannelGrid) / (buf.count + 1);
                end
                buf.count  = buf.count + 1;
                buf.nVar   = (buf.nVar * (buf.count - 1) + nVar) / buf.count;
                buf.intf   = intf;        % approximation: use latest resource intf
                buf.carrier = carrierConfigInfo;
                obj.CSIRSChannelBuffer = buf;

                if buf.count < numResources128T
                    % Not enough resources yet — return sentinel to defer report
                    dlRank = -1;
                    pmiSet = struct('i1', NaN(1,3), 'i2', NaN);
                    cqi = 0;  precodingMatrix = [];  sinr = -Inf;
                    return;
                end

                % All resources received: use averaged 128-port H for PMI
                estChannelGrid  = buf.H;         % [K x L x nRx x 128]
                nVar            = buf.nVar;
                intf            = buf.intf;
                carrierConfigInfo = buf.carrier;

                % Reset buffer for next period
                obj.CSIRSChannelBuffer = struct('H', [], 'count', 0, 'nVar', 0, ...
                                                'intf', [], 'carrier', []);

                % Build eTypeII-r19 report config for 128 ports.
                % Phase 3 will inject this via connectUE; here we derive a
                % default so that Phase 2 is immediately testable.
                reportCfg128 = obj.CSIReportConfig;
                if ~strcmpi(reportCfg128.CodebookType, 'eTypeII-r19')
                    % Build 128T eTypeII-r19 config as a struct so that all
                    % mandatory fields (NStartBWP, NSizeBWP, CQITable, etc.)
                    % are carried over from the validated base config.
                    reportCfg128.CodebookType                   = 'eTypeII-r19';
                    reportCfg128.PanelDimensions                = [1 16 4]; % N1=16,N2=4 → 128 ports
                    reportCfg128.NumberOfBeams                  = 2;        % L=2 (PC1, tractable)
                    reportCfg128.ParameterCombination           = 1;
                    reportCfg128.SubbandAmplitude               = false;    % wideband
                    % eTypeII-r19 specific fields not present in TypeI struct
                    reportCfg128.NumberOfPMISubbandsPerCQISubband = 1;
                end

                % Run PMI selection on aggregated 128-port channel
                [dlRank, pmiSet, pmiInfo] = nr5g.internal.nrRISelect(carrierConfigInfo, ...
                    csirsConfig, reportCfg128, estChannelGrid, nVar, 'MaxSE');
            else
                % ── Standard path (≤32T, single resource) ──────────────────
                if csirsConfig.NumCSIRSPorts > 1
                    [dlRank, pmiSet, pmiInfo] = nr5g.internal.nrRISelect(carrierConfigInfo, ...
                        csirsConfig, obj.CSIReportConfig, estChannelGrid, nVar, 'MaxSE');
                else
                    dlRank = 1;
                    pmiSet = struct('i1', [1 1 1], 'i2', 1);
                    pmiInfo.W = 1;
                end
            end

            % ── Step 3: CQI via LQM ─────────────────────────────────────────
            blerThreshold = 0.1;
            overhead = 0;
            if obj.CSIReferenceResource.NumLayers ~= dlRank
                obj.CSIReferenceResource.NumLayers = dlRank;
            end
            precodingMatrix = pmiInfo.W;

            % ThangTQ23_128T128R_Rel19 Phase 4/4b: pmiInfo.W may be 3-D
            % [numPorts×rank×numSubbands] when PMIMode='Subband'.
            numSBs = size(pmiInfo.W, 3); % 1 for wideband, >1 for subband

            useCQISubband = numSBs > 1 && ...
                            isfield(obj.CSIReportConfig, 'CQIMode') && ...
                            strcmpi(obj.CSIReportConfig.CQIMode, 'Subband');

            if useCQISubband
                % ── Phase 4b: per-subband CQI ──────────────────────────────
                % One L2SM call per subband using the subband's own precoder W.
                % Each call uses the FULL H (same carrier / csirsConfig) so no
                % dimension mismatch; only W varies per subband.
                % Result: cqi is [1 × numRBs] with per-RB values.
                cqiPerSB  = zeros(1, numSBs);
                sinrPerSB = zeros(1, numSBs);
                csRef = obj.CSIReferenceResource;  % value copy
                for sb = 1:numSBs
                    W_sb    = pmiInfo.W(:,:,sb).';   % [rank × numPorts]
                    l2sm_sb = obj.L2SMCSI;           % value copy — does not mutate obj.L2SMCSI
                    [l2sm_sb, sig_sb]  = nr5g.internal.L2SM.prepareLQMInput(l2sm_sb, ...
                        carrierConfigInfo, csirsConfig, estChannelGrid, nVar, W_sb);
                    [l2sm_sb, sinr_sb] = nr5g.internal.L2SM.linkQualityModel(l2sm_sb, sig_sb, intf);
                    [~, cqi_sb, cqiInfo_sb] = nr5g.internal.L2SM.cqiSelect(l2sm_sb, ...
                        carrierConfigInfo, csRef, overhead, sinr_sb, obj.CQITableValues, blerThreshold);
                    cqiPerSB(sb)  = max(cqi_sb, 1);
                    sinrPerSB(sb) = cqiInfo_sb.EffectiveSINR;
                end
                % Expand to per-RB: sbSizeRBs = NSizeGrid / numSBs
                sbSizeRBs = round(carrierConfigInfo.NSizeGrid / numSBs);
                cqi  = repelem(cqiPerSB, sbSizeRBs);  % [1 × numRBs]
                sinr = sinrPerSB(1);  % first-subband SINR for event logging
                % Update L2SMCSI state using subband-1 W (keeps the obj state consistent)
                W_lqm = pmiInfo.W(:,:,1).';
                [obj.L2SMCSI, ~] = nr5g.internal.L2SM.prepareLQMInput(obj.L2SMCSI, ...
                    carrierConfigInfo, csirsConfig, estChannelGrid, nVar, W_lqm);
            else
                % ── Wideband CQI (Phase 3 / fast path) ─────────────────────
                if numSBs > 1
                    W_lqm = pmiInfo.W(:,:,1).';  % subband PMI, wideband CQI: use sb-1 proxy
                else
                    W_lqm = pmiInfo.W.';          % true wideband W
                end
                [obj.L2SMCSI, sig] = nr5g.internal.L2SM.prepareLQMInput(obj.L2SMCSI, ...
                    carrierConfigInfo, csirsConfig, estChannelGrid, nVar, W_lqm);
                [obj.L2SMCSI, sinr] = nr5g.internal.L2SM.linkQualityModel(obj.L2SMCSI, sig, intf);
                [obj.L2SMCSI, cqi, cqiInfo] = nr5g.internal.L2SM.cqiSelect(obj.L2SMCSI, ...
                    carrierConfigInfo, obj.CSIReferenceResource, overhead, sinr, obj.CQITableValues, blerThreshold);
                cqi  = max([cqi, 1]);
                sinr = cqiInfo.EffectiveSINR;
            end

            % ThangTQ23_128T128R_Rel19: Live CSI feedback log — print UE-1 and UE-2 only.
            % Shows RI / CQI (per subband or wideband) / PMI i1 / SINR / overhead estimate.
            if rnti <= 2
                absSlot  = carrierConfigInfo.NFrame * carrierConfigInfo.SlotsPerFrame + carrierConfigInfo.NSlot;
                ri_bits  = 2;    % ceil(log2(maxRank=4))
                pmi_bits = 20;   % approx eTypeII-r19 L=2: beam indices + wideband amplitudes
                if useCQISubband
                    oh_cqi_bits = 4 + 2*(numSBs - 1);  % wideband base + differential subbands
                    cqi_str     = ['[' strtrim(num2str(cqiPerSB, '%d ')) '] (' num2str(numSBs) 'sb)'];
                    sinr_str    = ['[' strtrim(num2str(sinrPerSB, '%.1f ')) '] dB'];
                else
                    oh_cqi_bits = 4;
                    cqi_str     = sprintf('%d (WB)', cqi);
                    sinr_str    = sprintf('%.1f dB', sinr);
                end
                oh_total  = ri_bits + oh_cqi_bits + pmi_bits;
                % Show only first 3 i1 components (spatial beam indices) — eTypeII-r19 i1 has 28+ elements
                i1_disp = pmiSet.i1(1 : min(3, numel(pmiSet.i1)));
                i1_str  = strtrim(num2str(i1_disp, '%d '));
                fprintf('[CSI@slot%4d] UE-%-2d  RI=%d  CQI=%s  SINR=%s  i1=[%s]  OH~%d bits\n', ...
                    absSlot, rnti, dlRank, cqi_str, sinr_str, i1_str, oh_total);
            end
        end
    end

    methods (Access = private)
        function [crcFlag, sinr] = l2smCRC(obj, packetOfInterest, interferingPackets, estChannelGrid, ...
                estChannelGridsIntf, pdschInfo, carrierConfigInfo)
            % Return CRC flag (0 - success, 1 - failure)

            % Noise Variance
            nVar = calculateThermalNoise(obj);

            % Prepare LQM input for interferers
            intf = prepareLQMInputIntf(obj, obj.L2SMIUI, interferingPackets, estChannelGridsIntf, carrierConfigInfo, nVar);

            % Prepare LQM input for packet of interest
            % Extract PDSCH Indices for the packet of interest
            [~, info] = nrPDSCHIndices(carrierConfigInfo, pdschInfo.PDSCHConfig);
            % Prepare HARQ context for the packet of interest
            harqInfo = struct('HARQProcessID', pdschInfo.HARQID, 'RedundancyVersion', pdschInfo.RV, ...
                'TransportBlockSize', pdschInfo.TBS*8, 'NewData', pdschInfo.NewData);
            obj.L2SM = nr5g.internal.L2SM.txHARQ(obj.L2SM, harqInfo, pdschInfo.TargetCodeRate, info.G);
            % Prepare Link Quality Model inputs for the packet of interest
            [obj.L2SM, sig] = nr5g.internal.L2SM.prepareLQMInput(obj.L2SM,carrierConfigInfo, ...
                packetOfInterest.Metadata.PacketConfig, estChannelGrid, nVar, packetOfInterest.Metadata.PrecodingMatrix);

            % Link Quality Model (LQM) with signal of interest and interference
            [obj.L2SM,sinr] = nr5g.internal.L2SM.linkQualityModel(obj.L2SM,sig,intf);

            % Link Performance Model
            [obj.L2SM, crcFlag, cqiInfo] = nr5g.internal.L2SM.linkPerformanceModel(obj.L2SM,harqInfo,pdschInfo.PDSCHConfig,sinr);
            sinr = cqiInfo.EffectiveSINR;
        end
    end
end

