963	function [sinrIndices,sinrPRGSubs,sinrCRBSubs] = getSINRIndices(siz,carrier,ind,wtx)
964	
965	    % Get PRG subscripts, CRB subscripts and unique CRBs in PHY channel / 
966	    % signal indices
967	    ind = double(ind);
968	    [prgsubs,crbsubs] = nr5g.internal.prgSubscripts(siz,carrier.NStartGrid,ind,wtx);
969	    ucrb = unique(crbsubs).';
970	
971	    % Reduce indices to a single RE in each CRB, OFDM symbol and layer.
972	    % Also perform the same reduction on the PRG subscript CRBs and OFDM
973	    % symbols, and only keep the first layer because all layers will be in
974	    % the same PRG
975	    nucrb = numel(ucrb);
976	    P = size(ind,2);
977	    sinrIndices = zeros([0 P]);
978	    sinrPRGSubs = zeros([0 1]);
979	    sinrCRBSubs = zeros([0 1]);
980	    pshape = @(x)reshape(x,[],P);
981	    for i = 1:nucrb
982	        
983	        % Get indices and PRG subscripts in the current CRB
984	        thiscrb = (crbsubs==ucrb(i));
985	        crbIndices = pshape(ind(thiscrb));
986	        crbPRGSubs = pshape(prgsubs(thiscrb));
987	
988	        % For each OFDM symbol and layer, get indices and PRG subscripts
989	        % for the subcarrier closest to the middle of the CRB
990	        midk = ucrb(i)*12 + 6.5;
991	        [k,l,~] = ind2sub(siz,crbIndices);
992	        ul = unique(l).';
993	        nul = numel(ul);
994	        klpidx = zeros(nul,P);
995	        ek = abs(k - midk);
996	        for j = 1:nul
997	            ll = ul(j);
998	            lidx = find(l(:,1)==ll) + (0:P-1)*size(l,1);
999	            [~,kidx] = min(ek(lidx));
1000	            klpidx(j,:) = lidx(kidx + (0:P-1)*size(lidx,1));
