gNB = nrGNB( ...
    Position             = [0 0 30], ...
    TransmitPower        = 60, ...
    CarrierFrequency     = 4.9e9, ...
    ChannelBandwidth     = 10e6, ...
    SubcarrierSpacing    = 30e3, ...
    NumResourceBlocks    = 24, ...
    NumTransmitAntennas  = 128, ...
    NumReceiveAntennas   = 128, ...
    DuplexMode           = "TDD", ...
