    ResourceAllocationType = 0, ...
    MaxNumUsersPerTTI      = 32, ...
    MUMIMOConfigDL         = muMIMOConfiguration, ...
    CSIMeasurementSignalDL = "CSI-RS");

numUEs  = 8;   % small for speed
