    ReceiveGain         = 0, ...
    NumTransmitAntennas = 4, ...
    NumReceiveAntennas  = 4);

gNB.PMICQIMode = pmiCQIMode;
connectUE(gNB, UEs, FullBufferTraffic="DL", CSIReportPeriodicity=10);

addNodes(networkSimulator, gNB);
addNodes(networkSimulator, UEs);

channelConfig = struct(DelayProfile="CDL-B", DelaySpread=100e-9, MaximumDopplerShift=5);
channels = hNRCreateCDLChannels(channelConfig, gNB, UEs);
customChannelModel = hNRCustomChannelModel(channels);
addChannelModel(networkSimulator, @customChannelModel.applyChannelModel);

enableTraces = true;
simSchedulingLogger = helperNRSchedulingLogger(numFrameSimulation, gNB, UEs);
simPhyLogger        = helperNRPhyLogger(numFrameSimulation, gNB, UEs);

fprintf('\n=== Quick test: %d frames, %d UEs, Subband PMI ===\n\n', numFrameSimulation, numUEs);
run(networkSimulator, numFrameSimulation * 1e-2);

%% Results
metricsVisualizer = helperNRMetricsVisualizer(gNB, UEs, ...
    RefreshRate=1, PlotSchedulerMetrics=false, PlotPhyMetrics=false, ...
    PlotCDFMetrics=false, LinkDirection=0);
displayPerformanceIndicators(metricsVisualizer);

%% BLER check — Bug #1
logInfo = struct('TimeStepLogs', [], 'SchedulingAssignmentLogs', [], 'PhyReceptionLogs', []);
logInfo.TimeStepLogs            = getSchedulingLogs(simSchedulingLogger);
logInfo.SchedulingAssignmentLogs = getGrantLogs(simSchedulingLogger);
logInfo.PhyReceptionLogs        = getReceptionLogs(simPhyLogger);

rxLogs = logInfo.PhyReceptionLogs;
colMap = simPhyLogger.ReceptionLogsColumnIndexMap;
blerCol = colMap('BLER');
ueCol   = colMap('RNTI');

fprintf('\n--- Bug #1 check (BLER per UE, expect ~0.1 not ~0.6) ---\n');
for u = 1:numUEs
    mask = cell2mat(rxLogs(2:end, ueCol)) == u;
    if any(mask)
        blerVals = cell2mat(rxLogs(find(mask)+1, blerCol));
        fprintf('  UE-%d  BLER=%.3f\n', u, mean(blerVals));
    end
end

