pmiCQIMode         = "Wideband";   % avoids 6× subband LQM calls

networkSimulator = wirelessNetworkSimulator.init;

gNB = nrGNB( ...
    Position             = [0 0 30], ...
    TransmitPower        = 60, ...
    CarrierFrequency     = 4.9e9, ...
    ChannelBandwidth     = 10e6, ...
