  oLLA = struct('InitialOffset',0,'StepUp',0.27,'StepDown',0.03);
  configureScheduler(gNB,ResourceAllocationType=0,MaxNumUsersPerTTI=16, ...
    MUMIMOConfigDL=struct('MaxNumUsersPaired',4,'MaxNumLayers',8,'MinNumRBs',2,'SemiOrthogonalityFactor',0.5,'MinCQI',1), ...
    CSIMeasurementSignalDL='CSI-RS',LinkAdaptationConfigDL=oLLA);
  UEs = nrUE(Name='UE-'+(1:4),Position=repmat([100 0 0],4,1)+[0 0 30;50 0 0;-50 0 0;0 50 0], ...
    ReceiveGain=0,NumTransmitAntennas=4,NumReceiveAntennas=4);
  gNB.PMICQIMode='Wideband';
  connectUE(gNB,UEs,FullBufferTraffic='DL',CSIReportPeriodicity=10);
  addNodes(sim,gNB); addNodes(sim,UEs);
  ch=hNRCreateCDLChannels(struct('DelayProfile','CDL-B','DelaySpread',100e-9,'MaximumDopplerShift',5),gNB,UEs);
  cm=hNRCustomChannelModel(ch); addChannelModel(sim,@cm.applyChannelModel);
  fprintf('\n=== Wiring test: 3 frames — watch for [OLLA] lines ===\n');
  run(sim, 3*1e-2);
  fprintf('\nDone. If [OLLA] lines appeared above => OLLA is wired correctly.\n');
catch e
  fprintf('ERROR: %s  at %s line %d\n',e.message,e.stack(1).name,e.stack(1).line);
end
exit" 2>&1

